window.sendTelegramNotification=async function(o,e){const t=window.location.hostname==="localhost"||window.location.hostname==="127.0.0.1"?"http://localhost:3000":"https://api.orbitago.uz";try{const a=await fetch(t+"/api/telegram/notify",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({type:o,data:e})}),n=await a.json();return{success:a.ok,mode:"backend",data:n}}catch(a){return console.warn("Telegram bildirishnomasi yuborilmadi: backend server ishlamayapti.",a),{success:!1,error:"backend_unreachable"}}};
